import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Interview.css';

function Interview() {
  const navigate = useNavigate();
  const [step, setStep] = useState('upload'); // upload, interview, results
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [resumeData, setResumeData] = useState(null);
  const [sessionId, setSessionId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [currentAnswer, setCurrentAnswer] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [timeLimit, setTimeLimit] = useState(30); // minutes
  const [timeRemaining, setTimeRemaining] = useState(null);
  const [timerInterval, setTimerInterval] = useState(null);
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [isTerminating, setIsTerminating] = useState(false);

  // Toast notification function
  const showToast = (message, type = 'info') => {
    const toast = document.createElement('div');
    toast.className = `toast toast-${type}`;
    toast.textContent = message;
    document.body.appendChild(toast);

    setTimeout(() => toast.classList.add('show'), 10);
    setTimeout(() => {
      toast.classList.remove('show');
      setTimeout(() => document.body.removeChild(toast), 300);
    }, 3000);
  };

  // Fullscreen and security features during interview
  useEffect(() => {
    if (step === 'interview') {
      // Request fullscreen
      const enterFullscreen = async () => {
        try {
          const elem = document.documentElement;
          if (elem.requestFullscreen) {
            await elem.requestFullscreen();
          } else if (elem.webkitRequestFullscreen) {
            await elem.webkitRequestFullscreen();
          } else if (elem.msRequestFullscreen) {
            await elem.msRequestFullscreen();
          }
        } catch (err) {
          console.log('Fullscreen request failed:', err);
        }
      };
      enterFullscreen();

      // Warn before leaving page
      const handleBeforeUnload = (e) => {
        e.preventDefault();
        e.returnValue = 'Interview in progress. Are you sure you want to leave?';
        return e.returnValue;
      };

      // Prevent browser back button
      const handlePopState = (e) => {
        if (window.confirm('Interview in progress. Are you sure you want to leave?')) {
          return true;
        } else {
          window.history.pushState(null, '', window.location.pathname);
          e.preventDefault();
          return false;
        }
      };

      // Prevent copy/paste and keyboard shortcuts
      const handleKeyDown = (e) => {
        // Prevent Ctrl+C, Ctrl+V, Ctrl+X, Ctrl+A
        if ((e.ctrlKey || e.metaKey) && ['c', 'v', 'x', 'a'].includes(e.key.toLowerCase())) {
          e.preventDefault();
          showToast('Copy/Paste is disabled during the interview', 'warning');
          return false;
        }
        // Prevent F12, Ctrl+Shift+I (DevTools)
        if (e.key === 'F12' || ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'I')) {
          e.preventDefault();
          return false;
        }
      };

      // Prevent right-click context menu
      const handleContextMenu = (e) => {
        e.preventDefault();
        showToast('Right-click is disabled during the interview', 'warning');
        return false;
      };

      // Prevent copy event
      const handleCopy = (e) => {
        e.preventDefault();
        showToast('Copying is disabled during the interview', 'warning');
        return false;
      };

      // Prevent paste event
      const handlePaste = (e) => {
        // Allow paste only in textarea
        if (e.target.tagName !== 'TEXTAREA') {
          e.preventDefault();
          showToast('Pasting is disabled during the interview', 'warning');
          return false;
        }
      };

      // Prevent cut event
      const handleCut = (e) => {
        e.preventDefault();
        showToast('Cutting is disabled during the interview', 'warning');
        return false;
      };

      // Detect fullscreen exit - just try to re-enter
      const handleFullscreenChange = () => {
        if (!document.fullscreenElement && !document.webkitFullscreenElement && !document.msFullscreenElement) {
          // Try to re-enter fullscreen
          enterFullscreen();
        }
      };

      // Handle fullscreen violation (ESC key or exit fullscreen)
      const handleFullscreenViolation = async () => {
        setIsTerminating(true);

        // Clear timer
        if (timerInterval) {
          clearInterval(timerInterval);
        }

        // Show toast notification
        showToast('Interview terminated due to fullscreen exit', 'error');

        // Call backend to delete the interview
        try {
          const token = localStorage.getItem('token');
          await fetch(`http://localhost:5000/api/interview/${sessionId}/terminate`, {
            method: 'DELETE',
            headers: {
              'Authorization': `Bearer ${token}`,
              'Content-Type': 'application/json'
            }
          });
        } catch (error) {
          console.error('Failed to delete interview:', error);
        }

        // Redirect to dashboard
        setTimeout(() => {
          navigate('/dashboard');
        }, 2000);
      };

      // Add event listeners
      window.addEventListener('beforeunload', handleBeforeUnload);
      window.history.pushState(null, '', window.location.pathname);
      window.addEventListener('popstate', handlePopState);
      document.addEventListener('keydown', handleKeyDown);
      document.addEventListener('contextmenu', handleContextMenu);
      document.addEventListener('copy', handleCopy);
      document.addEventListener('paste', handlePaste);
      document.addEventListener('cut', handleCut);
      document.addEventListener('fullscreenchange', handleFullscreenChange);
      document.addEventListener('webkitfullscreenchange', handleFullscreenChange);
      document.addEventListener('msfullscreenchange', handleFullscreenChange);

      // Cleanup
      return () => {
        window.removeEventListener('beforeunload', handleBeforeUnload);
        window.removeEventListener('popstate', handlePopState);
        document.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('contextmenu', handleContextMenu);
        document.removeEventListener('copy', handleCopy);
        document.removeEventListener('paste', handlePaste);
        document.removeEventListener('cut', handleCut);
        document.removeEventListener('fullscreenchange', handleFullscreenChange);
        document.removeEventListener('webkitfullscreenchange', handleFullscreenChange);
        document.removeEventListener('msfullscreenchange', handleFullscreenChange);

        // Exit fullscreen when interview ends
        if (document.fullscreenElement) {
          document.exitFullscreen();
        } else if (document.webkitFullscreenElement) {
          document.webkitExitFullscreen();
        } else if (document.msFullscreenElement) {
          document.msExitFullscreen();
        }
      };
    }
  }, [step]);

  // Detect tab visibility change - STRICT MODE
  useEffect(() => {
    if (step === 'interview' && !isTerminating) {
      const handleVisibilityChange = async () => {
        if (document.hidden) {
          // User switched tabs - terminate interview immediately
          setIsTerminating(true);

          // Clear timer
          if (timerInterval) {
            clearInterval(timerInterval);
          }

          // Show toast notification
          showToast('⛔ TAB SWITCHING DETECTED! Interview terminated and deleted.', 'error');

          // Call backend to delete the interview
          try {
            const token = localStorage.getItem('token');
            await fetch(`http://localhost:5000/api/interview/${sessionId}/terminate`, {
              method: 'DELETE',
              headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
              }
            });
          } catch (error) {
            console.error('Failed to delete interview:', error);
          }

          // Exit fullscreen
          if (document.fullscreenElement) {
            document.exitFullscreen();
          } else if (document.webkitFullscreenElement) {
            document.webkitExitFullscreen();
          } else if (document.msFullscreenElement) {
            document.msExitFullscreen();
          }

          // Redirect to dashboard
          setTimeout(() => {
            navigate('/dashboard');
          }, 2000);
        }
      };

      document.addEventListener('visibilitychange', handleVisibilityChange);

      return () => {
        document.removeEventListener('visibilitychange', handleVisibilityChange);
      };
    }
  }, [step, sessionId, timerInterval, navigate, isTerminating]);

  // Timer management
  useEffect(() => {
    if (step === 'interview' && timeRemaining !== null) {
      const interval = setInterval(() => {
        setTimeRemaining(prev => {
          if (prev <= 1) {
            clearInterval(interval);
            handleTimeUp();
            return 0;
          }

          // Warnings at specific times
          if (prev === 300) { // 5 minutes
            alert('⏰ 5 minutes remaining!');
          } else if (prev === 60) { // 1 minute
            alert('⏰ 1 minute remaining!');
          }

          return prev - 1;
        });
      }, 1000);

      setTimerInterval(interval);

      return () => {
        if (interval) clearInterval(interval);
      };
    }
  }, [step, timeRemaining]);

  const handleTimeUp = async () => {
    alert('⏰ Time is up! Your interview will be completed automatically.');
    await handleCompleteInterview();
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getTimeColor = () => {
    if (!timeRemaining) return '#48bb78';
    const percentage = (timeRemaining / (timeLimit * 60)) * 100;
    if (percentage > 50) return '#48bb78'; // green
    if (percentage > 25) return '#ed8936'; // orange
    return '#f56565'; // red
  };

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile && selectedFile.type === 'application/pdf') {
      setFile(selectedFile);
    } else {
      alert('Please select a PDF file');
    }
  };

  const handleUpload = async () => {
    if (!file) return;

    setUploading(true);
    setError('');
    const formData = new FormData();
    formData.append('resume', file);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/resume/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });

      const data = await response.json();

      if (data.success) {
        setResumeData(data.resume);
        // Start interview session
        await startInterview(data.resume.id);
      } else {
        setError(data.message || 'Upload failed');
      }
    } catch (error) {
      setError('Network error. Please try again.');
    } finally {
      setUploading(false);
    }
  };

  const startInterview = async (resumeId) => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/interview/start', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ resumeId })
      });

      const data = await response.json();

      if (data.success) {
        setSessionId(data.session.id);
        setMessages([{
          type: 'ai',
          text: data.session.question
        }]);
        setTimeRemaining(timeLimit * 60); // Convert minutes to seconds
        setStep('interview');
      } else {
        setError(data.message || 'Failed to start interview');
      }
    } catch (error) {
      setError('Failed to start interview. Please try again.');
    }
  };

  const handleSendAnswer = async () => {
    if (!currentAnswer.trim() || loading) return;

    const userMessage = currentAnswer.trim();
    setCurrentAnswer('');
    setLoading(true);
    setError('');

    // Add user message to chat
    setMessages(prev => [...prev, {
      type: 'user',
      text: userMessage
    }]);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/answer`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ answer: userMessage })
      });

      const data = await response.json();

      if (data.success) {
        // Add AI response
        setMessages(prev => [...prev, {
          type: 'ai',
          text: data.question
        }]);
      } else {
        setError(data.message || 'Failed to get next question');
      }
    } catch (error) {
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCompleteInterview = async () => {
    if (!sessionId) return;

    // Clear timer
    if (timerInterval) {
      clearInterval(timerInterval);
    }

    setLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/complete`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      const data = await response.json();

      if (data.success) {
        // Redirect to dashboard to see results
        navigate('/dashboard');
      } else {
        setError(data.message || 'Failed to complete interview');
      }
    } catch (error) {
      setError('Failed to complete interview. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="interview-page">
      <div className="container-small">
        {error && <div className="alert alert-error">{error}</div>}

        {step === 'upload' && (
          <div className="upload-section fade-in">
            <h1>Upload Your Resume</h1>
            <p className="subtitle">Upload your resume to get personalized interview questions</p>

            <div className="upload-card">
              <div className="upload-icon">📄</div>
              <h3>Drag and drop your resume here</h3>
              <p>or click to browse (PDF only, max 3 pages)</p>

              <input
                type="file"
                accept=".pdf"
                onChange={handleFileChange}
                className="file-input"
                id="resume-upload"
              />
              <label htmlFor="resume-upload" className="btn btn-secondary">
                Choose File
              </label>

              {file && (
                <div className="file-selected">
                  <p>✓ {file.name}</p>
                  <button 
                    onClick={handleUpload} 
                    className="btn btn-primary"
                    disabled={uploading}
                  >
                    {uploading ? 'Processing...' : 'Start Interview'}
                  </button>
                </div>
              )}
            </div>

            <div className="upload-info">
              <h4>Requirements:</h4>
              <ul>
                <li>PDF format only</li>
                <li>Maximum 3 pages</li>
                <li>Clear, readable text</li>
                <li>Valid resume content</li>
              </ul>
            </div>

            <div className="time-selection">
              <h4>⏱️ Select Interview Duration:</h4>
              <div className="time-options">
                <button 
                  className={`time-option ${timeLimit === 30 ? 'active' : ''}`}
                  onClick={() => setTimeLimit(30)}
                >
                  <div className="time-value">30</div>
                  <div className="time-label">Minutes</div>
                </button>
                <button 
                  className={`time-option ${timeLimit === 60 ? 'active' : ''}`}
                  onClick={() => setTimeLimit(60)}
                >
                  <div className="time-value">60</div>
                  <div className="time-label">Minutes</div>
                </button>
                <button 
                  className={`time-option ${timeLimit === 120 ? 'active' : ''}`}
                  onClick={() => setTimeLimit(120)}
                >
                  <div className="time-value">120</div>
                  <div className="time-label">Minutes</div>
                </button>
              </div>
            </div>
          </div>
        )}

        {step === 'interview' && (
          <div className="interview-section fade-in">
            <div className="interview-warning">
              ⛔ STRICT MODE ACTIVE - Fullscreen required. Copy/Paste disabled. 
              <br />
              <strong>WARNING: Switching tabs (Alt+Tab/Ctrl+Tab) will IMMEDIATELY TERMINATE and DELETE this interview!</strong>
            </div>
            <div className="interview-header">
              <div>
                <h1>Interview in Progress</h1>
                <p className="subtitle">Answer the questions to the best of your ability</p>
              </div>
              <div className="interview-controls">
                {timeRemaining !== null && (
                  <div className="timer" style={{ color: getTimeColor() }}>
                    <span className="timer-icon">⏱️</span>
                    <span className="timer-value">{formatTime(timeRemaining)}</span>
                  </div>
                )}
                <button 
                  onClick={handleCompleteInterview} 
                  className="btn btn-secondary"
                  disabled={loading || messages.length < 4}
                >
                  Complete Interview
                </button>
              </div>
            </div>

            <div className="chat-container">
              {messages.map((msg, index) => (
                <div key={index} className={`message ${msg.type}-message`}>
                  <div className="message-avatar">
                    {msg.type === 'ai' ? '🤖' : '👤'}
                  </div>
                  <div className="message-content">
                    <p>{msg.text}</p>
                  </div>
                </div>
              ))}

              {loading && (
                <div className="message ai-message">
                  <div className="message-avatar">🤖</div>
                  <div className="message-content">
                    <p className="typing">Thinking...</p>
                  </div>
                </div>
              )}

              <div className="message-input-container">
                <textarea
                  className="message-input"
                  placeholder="Type your answer here..."
                  rows="4"
                  value={currentAnswer}
                  onChange={(e) => setCurrentAnswer(e.target.value)}
                  onKeyPress={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSendAnswer();
                    }
                  }}
                  disabled={loading}
                ></textarea>
                <button 
                  className="btn btn-primary" 
                  onClick={handleSendAnswer}
                  disabled={loading || !currentAnswer.trim()}
                >
                  {loading ? 'Sending...' : 'Send Answer'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Interview;
